import redis

class DistributedCache:
    def __init__(self, hosts):
        self.redis_client = redis.StrictRedisCluster(startup_nodes=hosts, decode_responses=True)

    def set_value(self, key, value, ttl=None):
        if ttl:
            return self.redis_client.setex(key, ttl, value)
        return self.redis_client.set(key, value)

    def get_value(self, key):
        return self.redis_client.get(key)

    def delete_key(self, key):
        return self.redis_client.delete(key)

# Example usage
if __name__ == "__main__":
    redis_hosts = [{"host": "redis_host1", "port": 6379}, {"host": "redis_host2", "port": 6379}]
    cache = DistributedCache(redis_hosts)
    
    session_token = cache.set_value("session:token:123", "abc123", ttl=3600)  # Store session token with TTL
    api_key = cache.set_value("api:key:456", "xyz789")  # Store API key without TTL
    
    print(cache.get_value("session:token:123"))  # Retrieve session token
    print(cache.get_value("api:key:456"))  # Retrieve API key
    
    cache.delete_key("session:token:123")  # Delete session token
    print(cache.get_value("session:token:123"))  # Verify deletion